func firstNestedObjectString(v any, objectKeys, valueKeys []string) string {
	objects := lowerSet(objectKeys)
	values := lowerSet(valueKeys)
	var walk func(any) string
	walk = func(cur any) string {
		switch x := cur.(type) {
		case map[string]any:
			for k, child := range x {
				if objects[strings.ToLower(k)] {
					if m, ok := child.(map[string]any); ok {
						for vk, vv := range m {
							if values[strings.ToLower(vk)] {
								if s := stringifyPreviewValue(vv); s != "" {
									return s
								}
							}
						}
					}
					if s := stringifyPreviewValue(child); s != "" {
						return s
					}
				}
			}
			for _, child := range x {
				if s := walk(child); s != "" {
					return s
				}
			}
		case []any:
			for _, child := range x {
				if s := walk(child); s != "" {
					return s
				}
			}
		}
		return ""
	}
	return walk(v)
}

func collectCheckoutItems(v any) []map[string]string {
	items := []map[string]string{}
	var walk func(any, string)
	walk = func(cur any, parentKey string) {
		if len(items) >= 25 {
			return
		}
		switch x := cur.(type) {
		case map[string]any:
			if strings.Contains(strings.ToLower(parentKey), "item") {
				name := firstStringByKeyShallow(x, []string{"name", "title", "displayName", "itemName"})
				if name != "" {
					items = append(items, map[string]string{
						"name":     name,
						"quantity": firstStringByKeyShallow(x, []string{"quantity", "qty", "itemQuantity"}),
						"price":    firstStringByKeyShallow(x, []string{"price", "unitPrice", "totalPrice", "subtotal", "lineItemTotal"}),
					})
				}
			}
			for k, child := range x {
				walk(child, k)
			}
		case []any:
			for _, child := range x {
				walk(child, parentKey)
			}
		}
	}
	walk(v, "")
	return dedupeStringMaps(items, "name", "price")
}

func collectCheckoutCharges(v any) []map[string]string {
	charges := []map[string]string{}
	var walk func(any, string)
	walk = func(cur any, parentKey string) {
		switch x := cur.(type) {
		case map[string]any:
			label := firstStringByKeyShallow(x, []string{"label", "name", "title", "displayName"})
			amount := firstStringByKeyShallow(x, []string{"amount", "value", "price", "displayString", "displayAmount"})
			lowerParent := strings.ToLower(parentKey)
			if label != "" && amount != "" && (strings.Contains(lowerParent, "fee") || strings.Contains(lowerParent, "tax") || strings.Contains(lowerParent, "tally") || strings.Contains(strings.ToLower(label), "fee") || strings.Contains(strings.ToLower(label), "tax") || strings.Contains(strings.ToLower(label), "discount")) {
				charges = append(charges, map[string]string{"label": label, "amount": amount})
			}
			for k, child := range x {
				lowerKey := strings.ToLower(k)
				if strings.Contains(lowerParent, "tally") || strings.Contains(lowerParent, "fee") || strings.Contains(lowerParent, "tax") {
					if strings.Contains(lowerKey, "fee") || strings.Contains(lowerKey, "tax") || strings.Contains(lowerKey, "discount") {
						if amount := stringifyPreviewValue(child); amount != "" {
							charges = append(charges, map[string]string{"label": k, "amount": amount})
						}
					}
				}
				walk(child, k)
			}
		case []any:
			for _, child := range x {
				walk(child, parentKey)
			}
		}
	}
	walk(v, "")
	return charges
}

func firstStringByKeyShallow(m map[string]any, keys []string) string {
	keySet := lowerSet(keys)
	for k, v := range m {
		if keySet[strings.ToLower(k)] {
			if s := stringifyPreviewValue(v); s != "" {
				return s
			}
		}
	}
	return ""
}

func stringifyPreviewValue(v any) string {
	switch x := v.(type) {
	case nil:
		return ""
	case string:
		return strings.TrimSpace(x)
	case float64:
		if x == float64(int64(x)) && x >= 100 {
			return fmt.Sprintf("$%.2f", x/100)
		}
		return strings.TrimRight(strings.TrimRight(fmt.Sprintf("%.2f", x), "0"), ".")
	case bool:
		return fmt.Sprintf("%t", x)
	case map[string]any:
		for _, key := range []string{"displayString", "formattedString", "displayAmount", "formattedAmount", "label", "name", "title", "value", "amount", "last4"} {
			if child, ok := x[key]; ok {
				if s := stringifyPreviewValue(child); s != "" {
					return s
				}
			}
		}
	case []any:
		parts := []string{}
		for _, child := range x {
			if s := stringifyPreviewValue(child); s != "" {
				parts = append(parts, s)
			}
		}
		return strings.Join(parts, ", ")
	}
	return ""
}

func lowerSet(keys []string) map[string]bool {
	set := make(map[string]bool, len(keys))
	for _, key := range keys {
		set[strings.ToLower(key)] = true
	}
	return set
}

func dedupeStringMaps(values []map[string]string, keys ...string) []map[string]string {
	seen := map[string]bool{}
	out := []map[string]string{}
	for _, value := range values {
		parts := []string{}
		for _, key := range keys {
			parts = append(parts, value[key])
		}
		fingerprint := strings.Join(parts, "\x00")
		if fingerprint == "" || seen[fingerprint] {
			continue
		}
		seen[fingerprint] = true
		out = append(out, value)
	}
	return out
}

// PATCH: Hard-gate DoorDash order placement so no command path can silently charge a card.
func validateOrderPlacementGate(flags *rootFlags, allowLiveOrderPlacement, ownerApproved bool, confirmation string) error {
	if flags != nil && flags.dryRun {
		return nil
	}
	missing := []string{}
	if !allowLiveOrderPlacement {
		missing = append(missing, "--enable-live-order-placement")
	}
	if !ownerApproved {
		missing = append(missing, "--owner-approved")
	}
	if confirmation != orderPlacementConfirmationPhrase {
		missing = append(missing, fmt.Sprintf("--confirm %q", orderPlacementConfirmationPhrase))
	}
	if len(missing) > 0 {
		return usageErr(fmt.Errorf("live DoorDash order placement is disabled by default; required gates: %v", missing))
	}
	return nil
}

func buildGraphQLBody(stdinBody bool, operationName, query, variables string, dryRun bool) (map[string]any, error) {
	if stdinBody {
		stdinData, err := io.ReadAll(os.Stdin)
		if err != nil {
			return nil, fmt.Errorf("reading stdin: %w", err)
		}
		var jsonBody map[string]any
		if err := json.Unmarshal(stdinData, &jsonBody); err != nil {
			return nil, fmt.Errorf("parsing stdin JSON: %w", err)
		}
		return jsonBody, nil
	}
	if !dryRun {
		if operationName == "" {
			return nil, fmt.Errorf("required flag %q not set", "operation-name")
		}
		if query == "" {
			return nil, fmt.Errorf("required flag %q not set", "query")
		}
		if variables == "" {
			return nil, fmt.Errorf("required flag %q not set", "variables")
		}
	}
	body := map[string]any{}
	if operationName != "" {
		body["operationName"] = operationName
	}
	if query != "" {
		resolvedQuery, err := resolveGraphQLDocument(query)
		if err != nil {
			return nil, err
		}
		body["query"] = resolvedQuery
	}
	if variables != "" {
		var parsedVariables any
		if err := json.Unmarshal([]byte(variables), &parsedVariables); err != nil {
			return nil, fmt.Errorf("parsing --variables JSON: %w", err)
		}
		body["variables"] = parsedVariables
	}
	return body, nil
}

func resolveGraphQLDocument(query string) (string, error) {
	// PATCH: Interpret curated query-file defaults as embedded GraphQL documents instead of sending file paths verbatim.
	if !strings.HasPrefix(query, "queries/") {
		return query, nil
	}
	data, err := cartGraphQLQueryFiles.ReadFile(query)
	if err != nil {
		return "", fmt.Errorf("loading embedded GraphQL document %q: %w", query, err)
	}
	return string(data), nil
}

func printMutationEnvelope(cmd *cobra.Command, flags *rootFlags, resource, path string, statusCode int, data json.RawMessage) error {
	if wantsHumanTable(cmd.OutOrStdout(), flags) {
		return printOutputWithFlags(cmd.OutOrStdout(), data, flags)
	}
	if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
		if flags.quiet {
			return nil
		}
		filtered := data
		if flags.selectFields != "" {
			filtered = filterFields(filtered, flags.selectFields)
		} else if flags.compact {
			filtered = compactFields(filtered)
		}
		envelope := map[string]any{
			"action":   "post",
			"resource": resource,
			"path":     path,
			"status":   statusCode,
			"success":  statusCode >= 200 && statusCode < 300,
		}
		if flags.dryRun {
			envelope["dry_run"] = true
			envelope["status"] = 0
			envelope["success"] = false
		}
		if len(filtered) > 0 {
			var parsed any
			if err := json.Unmarshal(filtered, &parsed); err == nil {
				envelope["data"] = parsed
			}
		}
		return json.NewEncoder(cmd.OutOrStdout()).Encode(envelope)
	}
	return printOutputWithFlags(cmd.OutOrStdout(), data, flags)
}
